import React, { useState } from 'react';

const Contact = () => {
  const [form, setForm] = useState({ name: '', email: '', message: '' });
  const [errors, setErrors] = useState({});
  const [submitted, setSubmitted] = useState(false);

  const validate = () => {
    const e = {};
    if (!form.name.trim()) e.name = 'Name is required.';
    if (!form.email.trim()) e.email = 'Email is required.';
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = 'Enter a valid email.';
    if (!form.message.trim()) e.message = 'Message cannot be empty.';
    return e;
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: '' });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length > 0) return setErrors(errs);
    setSubmitted(true);
  };

  const socialLinks = [
    { href: 'https://github.com/amd-16', img: '/images/github-logo.png', alt: 'GitHub' },
    { href: 'https://www.facebook.com/alihakim.dimacaling15', img: '/images/facebook-logo.png', alt: 'Facebook' },
    { href: 'mailto:example@gmail.com', img: '/images/gmail-logo.png', alt: 'Gmail' },
  ];

  return (
    <footer
      id="Contact"
      className="text-center mt-12 px-4 py-6 bg-[#f8f9fa]"
    >
      {/* Title */}
      <h5 className="italic text-gray-500 pt-1">
        Contact Me
      </h5>

      {/* Social Links */}
      <div className="flex justify-center items-center gap-5 mt-3">
        <p className="text-[#0d1117] text-sm">
          +639090909
        </p>

        {socialLinks.map((s) => (
          <a
            key={s.alt}
            href={s.href}
            target="_blank"
            rel="noreferrer"
            className="inline-block transition-transform hover:scale-110"
          >
            <img
              src={s.img}
              alt={s.alt}
              className="w-[50px] h-[50px]"
            />
          </a>
        ))}
      </div>

      {/* Form (optional but kept) */}
      <div className="max-w-md mx-auto mt-6 text-left">
        {!submitted ? (
          <form onSubmit={handleSubmit} className="flex flex-col gap-3">
            <input
              name="name"
              placeholder="Name"
              value={form.name}
              onChange={handleChange}
              className="w-full p-2 text-sm border border-gray-300 rounded"
            />
            {errors.name && <p className="text-xs text-red-500">{errors.name}</p>}

            <input
              name="email"
              placeholder="Email"
              value={form.email}
              onChange={handleChange}
              className="w-full p-2 text-sm border border-gray-300 rounded"
            />
            {errors.email && <p className="text-xs text-red-500">{errors.email}</p>}

            <textarea
              name="message"
              placeholder="Message"
              value={form.message}
              onChange={handleChange}
              rows={4}
              className="w-full p-2 text-sm border border-gray-300 rounded"
            />
            {errors.message && <p className="text-xs text-red-500">{errors.message}</p>}

            <button
              type="submit"
              className="bg-[#0d1117] text-white py-2 text-sm rounded hover:opacity-80 transition"
            >
              Send
            </button>
          </form>
        ) : (
          <p className="text-center text-green-600 font-semibold">
            Thanks {form.name}, message sent!
          </p>
        )}
      </div>

      {/* Footer bottom text */}
      <p className="text-[11px] mt-6 text-gray-600">
        © Alihakim M. Dimacaling. 2026 All rights reserved.
      </p>
    </footer>
  );
};

export default Contact;
